const email = $('Form Trigger').item.json['Email']?.trim();

if (!resumeText || resumeText.length < 50) {
  throw new Error('Could not extract text from resume. Please upload a text-based PDF.');
}

if (!jdText || jdText.length < 50) {
  throw new Error('Could not extract text from JD. Please upload a text-based PDF.');
}

if (!name || !email) {
  throw new Error('Name and email are required.');
}

return [
  {
    json: {
      name,
      email,
      resume: resumeText,
      jd: jdText
    }
  }
];

function extractJSON(raw) {
  if (!raw) throw new Error('Empty agent output');
  // Strip markdown fences
  let text = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  // Try direct parse
  try { return JSON.parse(text); } catch (_) {}
  // Find first { and last } — most reliable way to extract JSON
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    try { return JSON.parse(text.substring(start, end + 1)); } catch (e) {
      throw new Error('Found JSON block but failed to parse: ' + e.message);
    }
  }
  throw new Error('No JSON found in output: ' + text.substring(0, 120));
}


